function ajustarTelefone(raw) {
  if (!raw) return null;

  let t = raw.toString().replace(/\D/g, "");

  if (t.length === 11) t = "55" + t;
  if (t.length === 10) t = "55" + t;
  if (t.startsWith("55")) return t;
  if (t.startsWith("+")) return t.replace("+", "");

  return t;
}

// ========================================
// Identificar gatilho real (9h ou 10min)
// ========================================
let gatilho = null;

// tenta pegar dos possíveis nodes Set
try {
  gatilho = $('Seta o gatilho').first().json.gatilho || null;
} catch {}

try {
  gatilho = $('Seta o gatilho1').first().json.gatilho || gatilho;
} catch {}

try {
  gatilho = $('Seta o gatilho2').first().json.gatilho || gatilho;
} catch {}

if (!gatilho) {
  // fallback opcional
  gatilho = "10min"; 
}

// Lista final
const filtrados = [];

// ========================================================
// CASO 0 → Execução das 19h (Lembrete do dia anterior)
// ========================================================
if (gatilho === "19h") {
  const agora = new Date();

  // Cria uma data representando "Amanhã"
  const amanha = new Date(agora);
  amanha.setDate(amanha.getDate() + 1);

  // Formata para YYYY-MM-DD (ex: 2025-12-24)
  const dataAmanha = amanha.toISOString().split("T")[0];

  for (const item of items) {
    const lead = item.json;
    const telefone = lead.property_contato;
    const reuniao = lead.property_data_de_reuni_o?.start;

    if (!reuniao) continue;

    // Pega a data da reunião (YYYY-MM-DD)
    const dataReuniao = reuniao.split("T")[0];

    // Se a data da reunião for igual a data de amanhã
    if (dataReuniao === dataAmanha) {
      filtrados.push({
        json: {
          ...lead,
          telefonePadronizado: ajustarTelefone(telefone),
          motivo: "reuniao_amanha" // Use isso no Switch para mandar msg de "é amanhã"
        }
      });
    }
  }

  return filtrados;
}

// ========================================
// CASO 1 → Execução das 9h (gatilho = "9h")
// ========================================
if (gatilho === "9h") {
  const agora = new Date();
  const hoje = agora.toISOString().split("T")[0];

  for (const item of items) {
    const lead = item.json;
    const telefone = lead.property_contato;
    const reuniao = lead.property_data_de_reuni_o?.start;

    if (!reuniao) continue;

    const dataReuniao = reuniao.split("T")[0];

    if (dataReuniao === hoje) {
      filtrados.push({
        json: {
          ...lead,
          telefonePadronizado: ajustarTelefone(telefone),
          motivo: "reuniao_hoje"
        }
      });
    }
  }

  return filtrados;
}

// ========================================
// CASO 2 → Execução dos 21/51 min (10 min antes)
// ========================================
const agoraUTC = Date.now();
const min7 = agoraUTC + 7 * 60 * 1000;
const min12 = agoraUTC + 12 * 60 * 1000;

for (const item of items) {
  const lead = item.json;
  const telefone = lead.property_contato;
  const reuniao = lead.property_data_de_reuni_o?.start;

  if (!reuniao) continue;

  const timestampReuniao = new Date(reuniao).getTime();

  if (timestampReuniao >= min7 && timestampReuniao <= min12) {
    filtrados.push({
      json: {
        ...lead,
        telefonePadronizado: ajustarTelefone(telefone),
        motivo: "reuniao_proximos_10min"
      }
    });
  }
}

return filtrados;

// ==========================
// 1. DEFINIÇÃO DOS TEMPLATES
// ==========================
const templates = {
  // --- 10 MINUTOS ANTES ---
  reminder_reuniao: {
    name: "reminder_reuniao",
    vars: 2, // {{1}}=Nome, {{2}}=Link
    text: "Opa, {{1}}! Tudo certo por aí? \n\n Em 10 minutinhos a gente começa. Vou deixar o link aqui de novo pra facilitar: \n\n {{2}} \n\n Até já!"
  },
  reminder_reuniao_sem_link: {
    name: "reminder_reuniao_sem_link",
    vars: 1, // {{1}}=Nome
    text: "Oi, {{1}}! Tudo pronto aí? \n\n Nossa reunião começa em *10 minutos*. Te aguardo!"
  },

  // --- 9H DA MANHÃ (HOJE) ---
  reminder_reuniao2: {
    name: "reminder_reuniao2",
    vars: 3, // {{1}}=Nome, {{2}}=Horário, {{3}}=Link
    text: "Bom dia, {{1}}! Tudo bem? \n\n Passando só pra lembrar do nosso papo hoje às *{{2}}*. \n\n Já vou deixar o link aqui pra você se organizar: {{3}} \n\n Combinado? Até mais tarde!"
  },
  reminder_reuniao_sem_link2: {
    name: "reminder_reuniao_sem_link2",
    vars: 2, // {{1}}=Nome, {{2}}=Horário
    text: "Bom dia, {{1}}! Tudo bem? \n\n Passando pra lembrar da nossa reunião hoje às *{{2}}*. \n\n  Tudo certo pra gente conversar? Qualquer imprevisto me avisa!"
  },

  // --- 19H (DIA ANTERIOR - NOVO) ---
  reminder_reuniao_amanha: {
    name: "reminder_reuniao_amanha",
    vars: 2, // {{1}}=Nome, {{2}}=Horário
    text: "Boa noite, {{1}}!\n\nSó passando pra deixar no radar nossa reunião de amanhã às *{{2}}*.\n\nPodemos manter confirmado? Abs!"
  }
};

// ==========================
// 2. DADOS DO LEAD E ENTRADA
// ==========================
// A estrutura do 'items' pode variar dependendo do node anterior. 
// Assumindo que o node anterior retorna um array e estamos processando item a item ou o primeiro.
const leadData = items[0].json; 

// Tenta pegar dados enriquecidos do node anterior 'Preparar variáveis do lead' se existir
let origem = {};
try {
    origem = $('Preparar variáveis do lead').first().json;
} catch (e) {
    // Se falhar (ex: teste manual), usa o próprio json atual como fallback
    origem = leadData; 
}

// Dados básicos
const name = origem.name || leadData.name || "Visitante";
const telefone = String(origem.telefone || leadData.telefone || "");
const motivo = origem.motivo || leadData.motivo; // "reuniao_hoje", "reuniao_amanha", "reuniao_proximos_10min"

// Link da Reunião (Tenta pegar do Google Calendar ou Zoom)
const linkReuniao = 
  leadData.hangoutLink || 
  leadData.conferenceData?.entryPoints?.[0]?.uri || 
  leadData.location || // Às vezes o link tá no location
  null;

// Horário da Reunião (Formatado HH:MM)
const horarioReuniaoISO = leadData.start?.dateTime || leadData.start?.date || null;
let horarioFormatado = "";

if (horarioReuniaoISO) {
  const dt = new Date(horarioReuniaoISO);
  // Ajuste de fuso se necessário (o n8n geralmente traz ISO UTC ou com offset)
  // Se o servidor for UTC e a data vier com offset (-03:00), getHours pega hora local do servidor.
  // Para garantir hora do Brasil:
  const options = { timeZone: "America/Sao_Paulo", hour: '2-digit', minute: '2-digit', hour12: false };
  horarioFormatado = new Intl.DateTimeFormat('pt-BR', options).format(dt);
}

// ==========================
// 3. ESCOLHER O TEMPLATE CORRETO
// ==========================
let templateEscolhido = null;

if (motivo === "reuniao_amanha") {
    // Caso 19h (Dia anterior)
    templateEscolhido = templates.reminder_reuniao_amanha;
} 
else if (motivo === "reuniao_hoje") {
    // Caso 9h (Mesmo dia)
    templateEscolhido = linkReuniao 
        ? templates.reminder_reuniao2 
        : templates.reminder_reuniao_sem_link2;
} 
else {
    // Caso Default (10 min antes)
    templateEscolhido = linkReuniao 
        ? templates.reminder_reuniao 
        : templates.reminder_reuniao_sem_link;
}

// Se não achou template (erro de lógica), para aqui
if (!templateEscolhido) {
    throw new Error(`Nenhum template encontrado para o motivo: ${motivo}`);
}

// ==========================
// 4. MONTAR VARIÁVEIS (PARAMETERS)
// ==========================
const parameters = [];

// Variável {{1}} é SEMPRE o Nome
parameters.push({ type: "text", text: name });

// Lógica de variáveis adicionais baseada no Motivo
if (motivo === "reuniao_amanha") {
    // Template Amanhã: {{1}}=Nome, {{2}}=Horário
    parameters.push({ type: "text", text: horarioFormatado });
} 
else if (motivo === "reuniao_hoje") {
    // Template Hoje: {{1}}=Nome, {{2}}=Horário, {{3}}=Link (opcional)
    parameters.push({ type: "text", text: horarioFormatado });

    if (linkReuniao && templateEscolhido.vars >= 3) {
        parameters.push({ type: "text", text: linkReuniao });
    }
} 
else {
    // Template 10min: {{1}}=Nome, {{2}}=Link (se tiver link)
    if (linkReuniao && templateEscolhido.vars >= 2) {
        parameters.push({ type: "text", text: linkReuniao });
    }
}

// ==========================
// 5. MONTAR O PAYLOAD FINAL
// ==========================
const body = {
  messaging_product: "whatsapp",
  to: telefone,
  type: "template",
  template: {
    name: templateEscolhido.name,
    language: { code: "pt_BR" },
    components: [
      {
        type: "body",
        parameters: parameters
      }
    ]
  }
};

// ==========================
// 6. SIMULAR TEXTO FINAL (PARA LOG/DEBUG)
// ==========================
let textoSimulado = templateEscolhido.text;
textoSimulado = textoSimulado.replace("{{1}}", name);

if (motivo === "reuniao_amanha") {
    textoSimulado = textoSimulado.replace("{{2}}", horarioFormatado);
} 
else if (motivo === "reuniao_hoje") {
    textoSimulado = textoSimulado.replace("{{2}}", horarioFormatado);
    if (linkReuniao) textoSimulado = textoSimulado.replace("{{3}}", linkReuniao);
} 
else {
    if (linkReuniao) textoSimulado = textoSimulado.replace("{{2}}", linkReuniao);
}

// Limpa sobras de variáveis não preenchidas visualmente
textoSimulado = textoSimulado.replace(/{{[0-9]+}}/g, "");

// ==========================
// RETORNO
// ==========================
return {
  json: {
    resultado_api: body,
    mensagem_visual: textoSimulado,
    template_name: templateEscolhido.name,
    motivo_disparo: motivo,
    lead_nome: name,
    lead_telefone: telefone
  }
};
